import org.junit.jupiter.api.Test;

class LmdbLftjSpecializationTest {

	@Test
	void evaluateShouldBuildOneDerivedRelationForSamePredicateCycle() {
		LmdbLftjSyntheticScenario.TestQueryAccess queryAccess = new LmdbLftjSyntheticScenario.TestQueryAccess();
		QueryEvaluationStep evaluationStep = LmdbLftjSyntheticScenario.createEvaluationStep(queryAccess);

		long count = 0;
		try (CloseableIteration<BindingSet> iteration = evaluationStep.evaluate(EmptyBindingSet.getInstance())) {
			while (iteration.hasNext()) {
				iteration.next();
				count++;
			}
		}

		assertTrue(count > 0, "sanity check: the synthetic cycle must still produce rows");
		assertEquals(2, queryAccess.openTrieCursorCalls,
				"same-predicate cycle specialization should build one reusable relation from one forward and one reverse scan");
	}

	@Test
	void optimizerShouldFallbackForRepeatedVariablePattern() {
		LmdbLftjOptimizer optimizer = new LmdbLftjOptimizer(new LmdbLftjTripleSource(
				new LmdbLftjSyntheticScenario.EmptyTripleSource(),
				new OptimizerQueryAccess()));

		StatementPattern repeated = new StatementPattern(
				new Var("a"),
				new Var("pred", LmdbLftjSyntheticScenario.VF.createIRI("urn:p")),
				new Var("a"));
		StatementPattern second = new StatementPattern(
				new Var("a"),
				new Var("pred2", LmdbLftjSyntheticScenario.VF.createIRI("urn:q")),
				new Var("b"));
		StatementPattern third = new StatementPattern(
				new Var("b"),
				new Var("pred3", LmdbLftjSyntheticScenario.VF.createIRI("urn:r")),
				new Var("c"));
		TupleExpr tupleExpr = new QueryRoot(new Join(new Join(repeated, second), third));

		optimizer.optimize(tupleExpr, (Dataset) null, EmptyBindingSet.getInstance());

		assertFalse(((QueryRoot) tupleExpr).getArg() instanceof LmdbLftjTupleExpr,
				"repeated visible variables must stay on the generic evaluator path");
	}

	private static final class OptimizerQueryAccess extends LmdbLftjSyntheticScenario.TestQueryAccess {

		@Override
		public RecordIterator openScan(TxnManager.Txn txn, String indexName, long subj, long pred, long obj,
				long context, boolean explicit) {
			throw new UnsupportedOperationException();
		}

		@Override
		public LmdbTrieKeyCursor openTrieCursor(TxnManager.Txn txn, String indexName, boolean explicit) {
			throw new UnsupportedOperationException();
		}
	}
}
